/**
 * Pipe unary functions from left to right.
 * @param {...(value: unknown) => unknown} functions
 * @returns {(value: unknown) => unknown}
 */
export function pipe(...functions) {
  return (value) => {
    let current = value;
    for (const fn of functions) {
      current = fn(current);
    }
    return current;
  };
}

/**
 * Compose unary functions from right to left.
 * @param {...(value: unknown) => unknown} functions
 * @returns {(value: unknown) => unknown}
 */
export function compose(...functions) {
  return (value) => {
    let current = value;
    for (let index = functions.length - 1; index >= 0; index -= 1) {
      current = functions[index](current);
    }
    return current;
  };
}
